import{getDom}from"../../vanilla.js";import TomSelect from"../../tom-select.js";TomSelect.define("dropdown_header",function(e){var s=this;e=Object.assign({title:"Untitled",headerClass:"dropdown-header",titleRowClass:"dropdown-header-title",labelClass:"dropdown-header-label",closeClass:"dropdown-header-close",html:e=>'<div class="'+e.headerClass+'"><div class="'+e.titleRowClass+'"><span class="'+e.labelClass+'">'+e.title+'</span><a href="javascript:void(0)" class="'+e.closeClass+'">&times;</a></div></div>'},e),s.hook("after","setup",()=>{var l=getDom(e.html(e));s.dropdown.insertBefore(l,s.dropdown.firstChild)})});